USE EMADEDEV;DROP TABLE IF EXISTS EmadeCityPopulationCREATE TABLE EmadeCityPopulation (    state VARCHAR(50),    city VARCHAR(50),    population INT);INSERT INTO EmadeCityPopulation (state, city, population) VALUES ('California', 'Sacramento', 100);INSERT INTO EmadeCityPopulation (state, city, population) VALUES ('California', 'Los Angeles', 200);INSERT INTO EmadeCityPopulation (state, city, population) VALUES ('California', 'San Diego', 300);INSERT INTO EmadeCityPopulation (state, city, population) VALUES ('New York', '', 150);INSERT INTO EmadeCityPopulation (state, city, population) VALUES ('New York', 'Queens', 400);INSERT INTO EmadeCityPopulation (state, city, population) VALUES ('New York', 'Mahathan', 250);INSERT INTO EmadeCityPopulation (state, city, population) VALUES ('Texas', 'Dallas', 1000);INSERT INTO EmadeCityPopulation (state, city, population) VALUES ('Texas', 'Austin', 600);INSERT INTO EmadeCityPopulation (state, city, population) VALUES ('Texas', 'San Anthonio', 300);INSERT INTO EmadeCityPopulation (state, city, population) VALUES ('Florida', 'Miami', 900);INSERT INTO EmadeCityPopulation (state, city, population) VALUES ('Florida', 'Orlando', 400);INSERT INTO EmadeCityPopulation (state, city, population) VALUES ('Florida', 'Tampa', 200);-- find the cities with the maximum and minimum populations within each stateSelect *From EmadeCityPopulationWITH RankedCities AS (    SELECT         [state],         city,         [population],        RANK() OVER(PARTITION BY state ORDER BY population DESC) as max_rank,        RANK() OVER(PARTITION BY state ORDER BY population ASC) as min_rank    FROM EmadeCityPopulation    --WHERE city <> '' -- Optional: filters out the blank New York entry)SELECT     state,    MAX(CASE WHEN max_rank = 1 THEN city END) as max_pop_city,    MAX(CASE WHEN max_rank = 1 THEN population END) as max_population,    MAX(CASE WHEN min_rank = 1 THEN city END) as min_pop_city,    MAX(CASE WHEN min_rank = 1 THEN population END) as min_populationFROM RankedCitiesWHERE max_rank = 1 OR min_rank = 1GROUP BY [state];-- METHOD 1WITH CTE AS (SELECT *, dense_rank() OVER (PARTITION BY state ORDER BY population DESC) as max_population_rnk, dense_rank() OVER (PARTITION BY state ORDER BY population) as min_population_rnkFROM EmadeCityPopulation)SELECT state,	MAX(CASE WHEN max_population_rnk = 1 THEN city end) as max_population_city,   MAX( CASE WHEN min_population_rnk = 1 THEN city end) as min_population_cityFROM CTEGROUP BY stateORDER BY state;-- METHOD 2with cte as (SELECT *, 	MAX(population) OVER(PARTITION BY state)max_population,     MIN(population) OVER(PARTITION BY state) min_populationFROM EmadeCityPopulation)SELECT state,	MAX(CASE WHEN population = max_population THEN city end) max_population_city,    MAX(CASE WHEN population = min_population THEN city end) min_population_cityFROM cteGROUP BY stateORDER BY state;/*1, 2, 3, 4, 5 = Row number 1, 2, 2, 4, 5 = Rank1, 2, 2, 3, 4 = Dense Rank https://api.weather.gov/points/33.997,-118.4833https://apipheny.io/free-api/Emmanuel Olaiya 2:46https://api.weather.gov/gridpoints/LOX/146,44/forecast/hourly*/--REF VS CONSOLE APP EMADEBUSINESSAPP USING THIS BACKENDUSE EMADEDEVCREATE TABLE EmadeDetails(user_id INT PRIMARY KEY IDENTITY(1,1) NOT NULL,user_name VARCHAR(50) NOT NULL,user_age INT NOT NULL);--Check dataSELECT * FROM EmadeDetailsINSERT INTO EmadeDETAILS(user_name, user_age) VALUES('Emmanuel',10);